import { useEffect, useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { apiClient, authService } from "@/App";
import { toast } from "sonner";
import { Building2 } from "lucide-react";

const SchoolProfilePage = () => {
  const [loading, setLoading] = useState(true);
  const [editing, setEditing] = useState(false);
  const [logoPreview, setLogoPreview] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    address: "",
    phone: "",
    email: "",
    school_type: "",
    logo_url: "",
    motto: "",
    vision: "",
    mission: "",
    principal_name: "",
    website: "",
    established_year: ""
  });

  const user = authService.getUser();

  useEffect(() => {
    fetchSchoolProfile();
  }, []);

  const fetchSchoolProfile = async () => {
    try {
      if (user?.school_id) {
        const res = await apiClient.get(`/schools/${user.school_id}`);
        setFormData(res.data);
        if (res.data.logo_url) setLogoPreview(res.data.logo_url);
      }
    } catch {
      toast.error("Failed to load school");
    } finally {
      setLoading(false);
    }
  };

  const handleLogoUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      setLogoPreview(reader.result);
      setFormData({ ...formData, logo_url: reader.result });
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      if (!user?.school_id) {
        const res = await apiClient.post("/auth/register-school", {
          ...formData,
          admin_name: user?.full_name || "Admin",
          admin_email: user?.email,
          admin_password: "12345678",
          admin_phone: user?.phone || ""
        });

        toast.success("School created");
        window.location.href = `/s/${res.data.school_slug}`;
        return;
      }

      const clean = Object.fromEntries(
        Object.entries(formData).filter(([_, v]) => v !== "")
      );

      await apiClient.patch(`/schools/${user.school_id}`, clean);

      toast.success("Updated successfully");
      setEditing(false);
      fetchSchoolProfile();
    } catch {
      toast.error("Update failed");
    }
  };

  if (loading) {
    return (
      <div className="h-screen flex items-center justify-center text-gray-500">
        Loading dashboard...
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 p-6 space-y-6">

      {/* TOP BAR (Stripe style) */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-semibold tracking-tight">
            School Dashboard
          </h1>
          <p className="text-sm text-gray-500">
            Manage your institution profile
          </p>
        </div>

        {!editing ? (
          <Button onClick={() => setEditing(true)}>
            Edit Profile
          </Button>
        ) : (
          <Button variant="outline" onClick={() => setEditing(false)}>
            Cancel
          </Button>
        )}
      </div>

      {/* HERO SECTION */}
      {!editing && (
        <Card className="rounded-2xl border bg-white shadow-sm">
          <CardContent className="p-10 text-center space-y-5">

            {logoPreview ? (
              <img
                src={logoPreview}
                className="w-24 h-24 mx-auto rounded-xl object-contain"
              />
            ) : (
              <Building2 className="w-14 h-14 mx-auto text-gray-400" />
            )}

            <h2 className="text-3xl font-semibold">
              {formData.name || "Your School Name"}
            </h2>

            <p className="text-gray-500 italic">
              {formData.motto || "Add your motto"}
            </p>

            <div className="inline-flex px-3 py-1 rounded-full bg-gray-100 text-sm text-gray-600">
              {formData.school_type || "Institution"}
            </div>
          </CardContent>
        </Card>
      )}

      {/* GRID SECTION (Notion style blocks) */}
      {!editing && (
        <div className="grid md:grid-cols-3 gap-4">

          <Card><CardContent className="p-4">
            <p className="text-xs text-gray-500">Address</p>
            <p className="text-sm font-medium">{formData.address}</p>
          </CardContent></Card>

          <Card><CardContent className="p-4">
            <p className="text-xs text-gray-500">Phone</p>
            <p className="text-sm font-medium">{formData.phone}</p>
          </CardContent></Card>

          <Card><CardContent className="p-4">
            <p className="text-xs text-gray-500">Email</p>
            <p className="text-sm font-medium">{formData.email}</p>
          </CardContent></Card>

        </div>
      )}

      {/* VISION / MISSION */}
      {!editing && (
        <div className="grid md:grid-cols-2 gap-4">

          {formData.vision && (
            <Card className="border-l-4 border-blue-500">
              <CardContent className="p-5">
                <p className="text-xs text-gray-500 mb-2">VISION</p>
                <p className="text-sm">{formData.vision}</p>
              </CardContent>
            </Card>
          )}

          {formData.mission && (
            <Card className="border-l-4 border-emerald-500">
              <CardContent className="p-5">
                <p className="text-xs text-gray-500 mb-2">MISSION</p>
                <p className="text-sm">{formData.mission}</p>
              </CardContent>
            </Card>
          )}

        </div>
      )}

      {/* EXTRA INFO */}
      {!editing && (
        <Card>
          <CardContent className="p-5 grid md:grid-cols-3 gap-4 text-sm">

            <div>
              <p className="text-gray-500 text-xs">Principal</p>
              <p>{formData.principal_name}</p>
            </div>

            <div>
              <p className="text-gray-500 text-xs">Established</p>
              <p>{formData.established_year}</p>
            </div>

            <div>
              <p className="text-gray-500 text-xs">Website</p>
              <a className="text-blue-600" href={formData.website}>
                Open
              </a>
            </div>

          </CardContent>
        </Card>
      )}

      {/* ONBOARDING CTA */}
      {!editing && !user?.school_id && (
        <Button className="w-full" onClick={() => setEditing(true)}>
          Complete School Setup
        </Button>
      )}

      {/* EDIT MODE (clean SaaS form) */}
      {editing && (
        <form onSubmit={handleSubmit} className="space-y-4">

          <Card>
            <CardContent className="p-5 space-y-3">

              <Input placeholder="School Name"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              />

              <Input placeholder="Phone"
                value={formData.phone}
                onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
              />

              <Input placeholder="Email"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
              />

              <Textarea placeholder="Address"
                value={formData.address}
                onChange={(e) => setFormData({ ...formData, address: e.target.value })}
              />

              <Input placeholder="Motto"
                value={formData.motto}
                onChange={(e) => setFormData({ ...formData, motto: e.target.value })}
              />

              <Textarea placeholder="Vision"
                value={formData.vision}
                onChange={(e) => setFormData({ ...formData, vision: e.target.value })}
              />

              <Textarea placeholder="Mission"
                value={formData.mission}
                onChange={(e) => setFormData({ ...formData, mission: e.target.value })}
              />

              <Input placeholder="Principal"
                value={formData.principal_name}
                onChange={(e) => setFormData({ ...formData, principal_name: e.target.value })}
              />

              <Input placeholder="Established Year"
                value={formData.established_year}
                onChange={(e) => setFormData({ ...formData, established_year: e.target.value })}
              />

              <Input type="file" onChange={handleLogoUpload} />

              <Button type="submit" className="w-full bg-black text-white">
                Save Changes
              </Button>

            </CardContent>
          </Card>

        </form>
      )}

    </div>
  );
};

export default SchoolProfilePage;
